// Step 6 — WIRE IT ON: Confirm -> payment menu, and route all payment buttons.
// GUARDED swap: applies only if your rajathee.js matches the post-Step-5 version.
// NOTE: this makes the new checkout flow LIVE for Rajathee customers.
const fs=require('fs');const path=require('path');
const FILE=path.join(__dirname,'handlers','rajathee.js');
const ORIG=Buffer.from('','base64').toString('utf8');
const EDIT=Buffer.from('','base64').toString('utf8');
const cur=fs.readFileSync(FILE,'utf8');
if(cur===EDIT){console.log('⏭  Step 6 already applied.');process.exit(0);}
if(cur!==ORIG){console.error('❌ rajathee.js differs from the expected Step-5 version — NOT modifying. Send this to Claude.');process.exit(1);}
fs.writeFileSync(FILE,EDIT);
console.log('✅ Step 6 applied: payment menu wired on + all buttons routed. The new checkout is now LIVE after deploy.');
